import { useAuth } from 'metaowl'

class MyComponent extends Component {
  setup() {
    const { user, isLoggedIn, isLoading, login, logout } = useAuth()

    this.state = { user, isLoggedIn, isLoading }
    this.login = login
    this.logout = logout
  }
}

import { useLocalStorage } from 'metaowl'

class ThemeToggle extends Component {
  setup() {
    this.theme = useLocalStorage('theme', 'light')
  }

  toggle() {
    this.theme.value = this.theme.value === 'light' ? 'dark' : 'light'
    // Automatically saved to localStorage and synced to other tabs
  }
}

import { useFetch } from 'metaowl'

class UserList extends Component {
  setup() {
    const { data, loading, error, refresh } = useFetch('/api/users', {
      immediate: true,
      transform: (res) => res.results,
    })

    this.state = { data, loading, error }
    this.refresh = refresh
  }
}

import { useState } from '@odoo/owl'
import { useDebounce, useThrottle } from 'metaowl'

class SearchBox extends Component {
  setup() {
    this.query = useState({ value: '' })

    // Updates 400ms after the user stops typing
    this.debouncedQuery = useDebounce(this.query, 400)

    // Called at most once every 200ms
    this.throttledSearch = useThrottle((q) => this.search(q), 200)
  }
}

import { useWindowSize, useOnlineStatus } from 'metaowl'

class ResponsiveComponent extends Component {
  setup() {
    const { width, height } = useWindowSize()
    const isOnline = useOnlineStatus()

    this.state = { width, height, isOnline }
  }
}
